/* 1. TR_MORTGAGE (저당권 관련) */ SELECT TS.WORK_CD, TS.SERVICE_ID, TM.CAR_NO, TS.PROC_ST, TM.PAY_ST, TM.PAY_ME, TO_CHAR(TS.REQUEST_DT,'YYYYMMDD') as REQUEST_DT, TS.REQUEST_DT AS SORT_DT, TO_CHAR(TS.JUDGE_DT,'YYYYMMDD') as JUDGE_DT, TO_CHAR(TM.PAY_DT,'YYYYMMDD') as PAY_DT, TM.VBANK_NO, TM.TOTAL_AMT, TMD.MEMBER_NM, TB.BRANCH_NM, TS.MEMBER_ID, TC.COMPANY_NM, DECODE(TS.WORK_CD, '000', TM.MORT_NM, TM.PAY_NM) as REQUEST_NM, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'FEE') FEE_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'STAMP') STAMP_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'REGIS') REGIS_AMT, (SELECT VBANK_NO FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'REGIS') EPAY_NO, (SELECT VBANK_NO FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'UREG') UREG_EPAY_NO, 0 PRE_ACQ_AMT, 0 ACQ_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'INJI') INJI_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'BOND') BOND_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'BFEE') BFEE_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'TMAN') TMAN_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'TPROX') TPROX_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'TNUM') NUMP_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'UNUM') NUMP_PROXY_AMT, (SELECT CONFIRM_NO FROM TR_MORTGAGE WHERE SERVICE_ID = TS.SERVICE_ID) as CONFIRM_NO, TM.DSIGN_GB, TS.GOVT_ID, TM.PAY_TP, TCI.CARID_NO, '' AS INJI_NO, DECODE(TS.WORK_CD, '000', TM.MORT_NM, '001', TM.PAY_NM) as CU_NAME, DECODE(TS.WORK_CD, '000', '2', '') as REG_GB, DECODE(TS.WORK_CD, '000', TC.COMPANY_NO, '') as REG_NO, '' as CAR_NM, '' as GOVT_TX, (SELECT DECODE(COUNT(*), 0, 0, COUNT(*)-1) FROM TR_JOINT WHERE SERVICE_ID = TS.SERVICE_ID) AS MORT_COUNT, '' as BASE_ADDRESS, 0 ORIX_NEWCAR_AMT, '' as TASK_CD FROM TR_SERVICE TS, TR_MORTGAGE TM, TM_MEMBER_DT TMD, TM_COMPANY TC, TM_BRANCH TB, TR_CARINFO TCI WHERE TS.SERVICE_ID = TM.SERVICE_ID AND TS.ASSOCIATION_ID = TMD.ASSOCIATION_ID AND TS.COMPANY_ID = TMD.COMPANY_ID AND TS.MEMBER_ID = TMD.MEMBER_ID AND TS.ASSOCIATION_ID = TC.ASSOCIATION_ID AND TS.COMPANY_ID = TC.COMPANY_ID AND TS.COMPANY_ID = TB.COMPANY_ID AND TS.BRANCH_ID = TB.BRANCH_ID AND TS.SERVICE_ID = TCI.SERVICE_ID
UNION ALL
/* 2. TR_TRNSNAME (이전등록 관련) */ SELECT TS.WORK_CD, TS.SERVICE_ID, TM.CAR_NO, TS.PROC_ST, TM.PAY_ST, TM.PAY_ME, TO_CHAR(TS.REQUEST_DT, 'YYYYMMDD') as REQUEST_DT, TS.REQUEST_DT AS SORT_DT, TO_CHAR(TS.JUDGE_DT, 'YYYYMMDD') as JUDGE_DT, TO_CHAR(TM.PAY_DT, 'YYYYMMDD') as PAY_DT, TM.VBANK_NO, TM.TOTAL_AMT, NVL(TMD.MEMBER_NM, '다코스대행') AS MEMBER_NM, TB.BRANCH_NM, TS.MEMBER_ID, TC.COMPANY_NM, TNB.BUY_NM as REQUEST_NM, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'FEE') FEE_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'STAMP') STAMP_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'UREG') REGIS_AMT, (SELECT VBANK_NO FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'ACQ') EPAY_NO, (SELECT VBANK_NO FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'UREG') UREG_EPAY_NO, 0 PRE_ACQ_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'ACQ') ACQ_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'INJI') INJI_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'BOND') BOND_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'BFEE') BFEE_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'MCHG') TMAN_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'TPROX') TPROX_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'TNUM') NUMP_AMT, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'UNUM') NUMP_PROXY_AMT, (SELECT CONFIRM_NO FROM TR_DSIGN WHERE SERVICE_ID = TS.SERVICE_ID AND DSIGN_SEQ = 1) as CONFIRM_NO, TNS.DSIGN_GB as DSIGN_GB, TS.GOVT_ID, TM.PAY_TP as PAY_TP, TM.CARID_NO, TM.INJI_NO, TNB.BUY_NM as CU_NAME, DECODE(TNB.REG_GB, 'R', '1', 'F', '1', '2') as REG_GB, DECODE(TNB.REG_GB, 'R', SUBSTR(PKG_COMMON.FN_DECRYPT(TNB.REG_NO), 1, 6), 'F', SUBSTR(PKG_COMMON.FN_DECRYPT(TNB.REG_NO), 1, 6), PKG_COMMON.FN_DECRYPT(TNB.REG_NO)) as REG_NO, (SELECT VBANK_NO FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'MCHG') as CAR_NM, '' as GOVT_TX, 0 AS MORT_COUNT, '' as BASE_ADDRESS, 0 ORIX_NEWCAR_AMT, '' as TASK_CD FROM TR_SERVICE TS, TR_TRNSNAME TM, TR_TRNSNAME_BUY TNB, TR_TRNSNAME_SELL TNS, TM_MEMBER_DT TMD, TM_COMPANY TC, TM_BRANCH TB WHERE TS.SERVICE_ID = TM.SERVICE_ID AND TS.SERVICE_ID = TNB.SERVICE_ID AND TS.SERVICE_ID = TNS.SERVICE_ID AND TS.ASSOCIATION_ID = TMD.ASSOCIATION_ID(+) AND TS.COMPANY_ID = TMD.COMPANY_ID(+) AND TS.MEMBER_ID = TMD.MEMBER_ID(+) AND TS.ASSOCIATION_ID = TC.ASSOCIATION_ID AND TS.COMPANY_ID = TC.COMPANY_ID AND TS.COMPANY_ID = TB.COMPANY_ID AND TS.BRANCH_ID = TB.BRANCH_ID
AND TM.TASK_CD = #{TASK_CD}
UNION ALL /* 3. TR_CARNO_DETACH (번호판 반납/교체) */ SELECT '032', TS.SERVICE_ID, TCD.POST_CAR_NO, TS.PROC_ST, TM.PAY_ST, TM.PAY_ME, TO_CHAR(TS.REQUEST_DT, 'YYYYMMDD') as REQUEST_DT, TS.REQUEST_DT AS SORT_DT, TO_CHAR(TS.JUDGE_DT, 'YYYYMMDD') as JUDGE_DT, TO_CHAR(TM.PAY_DT, 'YYYYMMDD') as PAY_DT, TM.VBANK_NO, TM.TOTAL_AMT, NVL(TMD.MEMBER_NM, '다코스대행'), TB.BRANCH_NM, TS.MEMBER_ID, TC.COMPANY_NM, TNB.BUY_NM, 0, 0, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'MCHG'), (SELECT VBANK_NO FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'MCHG'), (SELECT VBANK_NO FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'UREG'), 0, 0, 0, 0, 0, 0, 0, 0, 0, (SELECT CONFIRM_NO FROM TR_DSIGN WHERE SERVICE_ID = TS.SERVICE_ID AND DSIGN_SEQ = 1), TNS.DSIGN_GB, TS.GOVT_ID, TM.PAY_TP, TM.CARID_NO, '', TNB.BUY_NM, DECODE(TNB.REG_GB, 'R', '1', 'F', '1', '2'), DECODE(TNB.REG_GB, 'R', SUBSTR(PKG_COMMON.FN_DECRYPT(TNB.REG_NO), 1, 6), 'F', SUBSTR(PKG_COMMON.FN_DECRYPT(TNB.REG_NO), 1, 6), PKG_COMMON.FN_DECRYPT(TNB.REG_NO)), '', '', 0, '', 0, '' FROM TR_SERVICE TS, TR_TRNSNAME TM, TR_TRNSNAME_BUY TNB, TR_TRNSNAME_SELL TNS, TM_MEMBER_DT TMD, TM_COMPANY TC, TM_BRANCH TB, TR_CARNO_DETACH TCD WHERE TS.SERVICE_ID = TM.SERVICE_ID AND TS.SERVICE_ID = TNB.SERVICE_ID AND TS.SERVICE_ID = TNS.SERVICE_ID AND TS.SERVICE_ID = TCD.SERVICE_ID AND TS.ASSOCIATION_ID = TMD.ASSOCIATION_ID(+) AND TS.COMPANY_ID = TMD.COMPANY_ID(+) AND TS.MEMBER_ID = TMD.MEMBER_ID(+) AND TS.ASSOCIATION_ID = TC.ASSOCIATION_ID AND TS.COMPANY_ID = TC.COMPANY_ID AND TS.COMPANY_ID = TB.COMPANY_ID AND TS.BRANCH_ID = TB.BRANCH_ID AND (TM.CAR_NO LIKE '%하%' OR TM.CAR_NO LIKE '%허%' OR TM.CAR_NO LIKE '%호%')
UNION ALL /* 4. TR_MODIFY (변경등록 관련) */ SELECT TS.WORK_CD, TS.SERVICE_ID, TM.CAR_NO, TS.PROC_ST, TM.PAY_ST, TM.PAY_ME, TO_CHAR(TS.REQUEST_DT, 'YYYYMMDD') as REQUEST_DT, TS.REQUEST_DT AS SORT_DT, TO_CHAR(TS.JUDGE_DT, 'YYYYMMDD') as JUDGE_DT, TO_CHAR(TM.PAY_DT, 'YYYYMMDD') as PAY_DT, TM.VBANK_NO, TM.TOTAL_AMT, NVL(TMD.MEMBER_NM, '다코스대행'), TB.BRANCH_NM, TS.MEMBER_ID, TC.COMPANY_NM, TM.OWNER_NM, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'FEE'), (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'STAMP'), (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'REGIS'), (SELECT VBANK_NO FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'REGIS'), (SELECT VBANK_NO FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'UREG'), 0, 0, 0, 0, 0, 0, 0, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'TNUM'), (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'UNUM'), (SELECT CONFIRM_NO FROM TR_DSIGN WHERE SERVICE_ID = TS.SERVICE_ID AND DSIGN_SEQ = 1), '', TS.GOVT_ID, 'GUN', TM.CARID_NO, '', TM.OWNER_NM, DECODE(TM.REG_GB, 'R', '1', 'F', '1', '2'), DECODE(TM.REG_GB, 'R', SUBSTR(PKG_COMMON.FN_DECRYPT(TM.REG_NO), 1, 6), 'F', SUBSTR(PKG_COMMON.FN_DECRYPT(TM.REG_NO), 1, 6), PKG_COMMON.FN_DECRYPT(TM.REG_NO)), '', '', 0, '', 0, '' FROM TR_SERVICE TS, TR_MODIFY TM, TM_MEMBER_DT TMD, TM_COMPANY TC, TM_BRANCH TB WHERE TS.SERVICE_ID = TM.SERVICE_ID AND TS.ASSOCIATION_ID = TMD.ASSOCIATION_ID(+) AND TS.COMPANY_ID = TMD.COMPANY_ID(+) AND TS.MEMBER_ID = TMD.MEMBER_ID(+) AND TS.ASSOCIATION_ID = TC.ASSOCIATION_ID AND TS.COMPANY_ID = TC.COMPANY_ID AND TS.COMPANY_ID = TB.COMPANY_ID AND TS.BRANCH_ID = TB.BRANCH_ID
UNION ALL /* 5. TR_NEWCAR (신규등록 관련) */ SELECT TS.WORK_CD, TS.SERVICE_ID, TM.CAR_NO, TS.PROC_ST, TM.PAY_ST, TM.PAY_ME, TO_CHAR(TS.REQUEST_DT, 'YYYYMMDD') as REQUEST_DT, TS.REQUEST_DT AS SORT_DT, TO_CHAR(TS.JUDGE_DT, 'YYYYMMDD') as JUDGE_DT, TO_CHAR(TM.PAY_DT, 'YYYYMMDD') as PAY_DT, TM.VBANK_NO, TM.TOTAL_AMT, NVL(TMD.MEMBER_NM, '다코스대행'), TB.BRANCH_NM, TS.MEMBER_ID, TC.COMPANY_NM, TM.OWNER_NM, (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'FEE'), (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'STAMP'), (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'UREG'), (SELECT VBANK_NO FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'ACQ'), (SELECT VBANK_NO FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'UREG'), (SELECT PRE_PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'ACQ'), (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'ACQ'), (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'INJI'), (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'BOND'), (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'BFEE'), (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'TMAN'), (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'TPROX'), (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'TNUM'), (SELECT PAY_AMT FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD = 'UNUM'), (SELECT CONFIRM_NO FROM TR_DSIGN WHERE SERVICE_ID = TS.SERVICE_ID AND DSIGN_SEQ = 1), '', TS.GOVT_ID, TM.BOND_DC, TM.CARID_NO, TM.INJI_NO, TM.OWNER_NM, DECODE(TM.REG_GB, 'R', '1', 'F', '1', '2'), DECODE(TM.REG_GB, 'R', SUBSTR(PKG_COMMON.FN_DECRYPT(TM.REG_NO), 1, 6), 'F', SUBSTR(PKG_COMMON.FN_DECRYPT(TM.REG_NO), 1, 6), PKG_COMMON.FN_DECRYPT(TM.REG_NO)), TM.CAR_NM, TM.GOVT_TX, 0, PKG_COMMON.FN_DECRYPT(TM.BASE_ADDRESS), (SELECT SUM(PAY_AMT) FROM TR_PAYMENT TP WHERE TP.SERVICE_ID = TS.SERVICE_ID AND PAY_KD IN ('FEE','BOND','BFEE','TNUM', 'UNUM')), TM.TASK_CD FROM TR_SERVICE TS, TR_NEWCAR TM, TM_MEMBER_DT TMD, TM_COMPANY TC, TM_BRANCH TB WHERE TS.SERVICE_ID = TM.SERVICE_ID AND TS.ASSOCIATION_ID = TMD.ASSOCIATION_ID(+) AND TS.COMPANY_ID = TMD.COMPANY_ID(+) AND TS.MEMBER_ID = TMD.MEMBER_ID(+) AND TS.ASSOCIATION_ID = TC.ASSOCIATION_ID AND TS.COMPANY_ID = TC.COMPANY_ID AND TS.COMPANY_ID = TB.COMPANY_ID AND TS.BRANCH_ID = TB.BRANCH_ID
AND TM.IMSIGV_CD = #{GOVT_ID} AND (TM.IMSIGV_CD <> #{GOVT_ID} OR TM.IMSIGV_CD IS NULL)
ORDER BY SORT_DT DESC

