mapper.select:
SELECT TV.TVBANK_ID, TV.COMPANY_ID, TC.COMPANY_NM, TV.VBANK_NO, TV.USE_YN, TV.BALANCE_AMT FROM TM_TVBANK_MANAGE TV, TM_COMPANY TC WHERE TV.COMPANY_ID = TC.COMPANY_ID(+)
AND TV.COMPANY_ID = #{COMPANY_ID}
ORDER BY TV.COMPANY_ID

SELECT PO.POINT_ID, PO.COMPANY_ID, TC.COMPANY_NM, PO.POINT_AMT, PO.USE_AMT, PO.REMAIN_AMT, TO_CHAR(PO.REG_DT, 'YYYYMMDD') AS REG_DT FROM TM_POINT_MANAGE PO, TM_COMPANY TC WHERE PO.COMPANY_ID = TC.COMPANY_ID(+)
AND PO.COMPANY_ID = #{COMPANY_ID}
ORDER BY PO.REG_DT DESC

SELECT TS.SERVICE_ID, TS.WORK_CD, TS.CAR_NO, TS.COMPANY_ID, TC.COMPANY_NM, TO_CHAR(TS.REQUEST_DT, 'MM.DD HH24:MI') AS REQUEST_DT, TS.PROC_ST FROM TR_SERVICE TS, TM_COMPANY TC WHERE TS.COMPANY_ID = TC.COMPANY_ID AND TS.REQUEST_DT BETWEEN TO_DATE(#{START_DT} || '00:00:00', 'YYYYMMDDHH24:MI:SS') AND TO_DATE(#{END_DT} || '23:59:59', 'YYYYMMDDHH24:MI:SS')
AND TS.COMPANY_ID = #{COMPANY_ID}
AND TS.WORK_CD = #{WORK_CD}
ORDER BY TS.REQUEST_DT DESC
